resource "aws_iam_role" "synthetic_role_128" {
  name = "synthetic_role_128"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_128_policy" {
  name   = "synthetic_role_128-policy"
  role   = aws_iam_role.synthetic_role_128.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "rds:ModifyDBInstance",
                "rds:*",
                "rds:DeleteDBInstance"
            ],
            "Resource": "arn:aws:rds:*:*:*",
            "Condition": {
                "StringEquals": {
                    "aws:PrincipalType": "Service"
                }
            }
        }
    ]
})
}
